BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?pkgName ?child ?childType ?childName WHERE {
  VALUES (?pkg ?pkgName) {
    (http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::09%2520Views::TMT-APS-SE http://api.koneksys.com/cameo/TMT-APS-SE)
  }
  ?pkg vocab:NamedElement_name ?pkgName2 .
  FILTER(STR(?pkgName2) = "TMT-APS-SE")

  ?pkg vocab:Package_packagedElement ?child .
  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?pkg ?pkgName ?child ?childType ?childName WHERE {
  ?pkg rdf:type vocab:package .
  ?pkg vocab:NamedElement_name ?pkgName .
  FILTER(STR(?pkgName) = "TMT-APS-SE")

  ?pkg vocab:Package_packagedElement ?child .
  OPTIONAL { ?child rdf:type ?childType . }
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childName ?childType WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name "TMT-APS-SE" ;
       vocab:Package_packagedElement ?child .

  ?child vocab:NamedElement_name ?childName .
  OPTIONAL { ?child rdf:type ?childType . }

  FILTER(
    CONTAINS(LCASE(STR(?childName)), LCASE("view"))
    || CONTAINS(LCASE(STR(?childName)), LCASE("analysis"))
    || CONTAINS(LCASE(STR(?childName)), LCASE("ddd"))
    || CONTAINS(LCASE(STR(?childName)), LCASE("requirements"))
    || CONTAINS(LCASE(STR(?childName)), LCASE("icd"))
  )
}
ORDER BY ?childName
LIMIT 25
